import{_ as t,n as a,v as s,ac as i}from"./chunks/framework.DFVDdn94.js";const o="/blog/_project/01.png",c="/blog/_project/02.png",p="/blog/_project/03.png",u=JSON.parse('{"title":"基于 whistle + SwitchyOmega 的前端代理方案","description":"","frontmatter":{},"headers":[],"relativePath":"_project/03-webfront-proxy.md","filePath":"_project/03-webfront-proxy.md","lastUpdated":1750408780000}'),l={name:"_project/03-webfront-proxy.md"};function d(h,e,r,n,g,k){return s(),a("div",null,e[0]||(e[0]=[i('<h1 id="基于-whistle-switchyomega-的前端代理方案" tabindex="-1">基于 whistle + SwitchyOmega 的前端代理方案 <a class="header-anchor" href="#基于-whistle-switchyomega-的前端代理方案" aria-label="Permalink to &quot;基于 whistle + SwitchyOmega 的前端代理方案&quot;">​</a></h1><div class="note custom-block github-alert"><p class="custom-block-title">NOTE</p><p>  在目前的前端开发过程中，虽然有 <code>vite</code> <code>webpack</code> 等工具可以启动服务便于本地调试。或者更改 <code>api</code> 地址达到直接用测试或生产数据进行调试。</p><p>  但是，由于各种各样的依赖问题导致，更改环境也不能保证项目在本地的正常运行（比如基于 <code>cookie</code> 鉴权）。又或者在微前端的子应用调整的时候不想频繁的启动主应用。</p><p>  该代理的方案就是让用户在本地调试的时候，浏览器上虽然是测试环境的域名，但是本地修改代码的效果可以直接展示到浏览器上。方便 <code>bug</code> 的复现与修改。</p></div><h2 id="安装-配置-whistle" tabindex="-1">安装 &amp; 配置 whistle <a class="header-anchor" href="#安装-配置-whistle" aria-label="Permalink to &quot;安装 &amp; 配置 whistle&quot;">​</a></h2><p><a href="https://github.com/avwo/whistle" target="_blank" rel="noreferrer">地址</a> 安装方式两种，<code>npm</code> 和 <code>brew</code>。我选择了后者</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">brew</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> install</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> whistle</span></span></code></pre></div><p>成功之后入 <code>w2 start</code> 启动 <code>whistle</code>。默认占用端口为 <code>8899</code></p><p><img src="'+o+'" alt="alt text"></p><p>打开链接进入控制台注意以下两处</p><ul><li>点击侧边栏 <code>rules</code> 添加规则，以图为例，本地为 <code>vite</code> 项目前面为测试环境域名。</li><li>点击顶栏 <code>https</code> 下载证书，然后将证书安装到钥匙串中，然后信任证书（仅针对 MacOS 系统）。</li></ul><p><img src="'+c+'" alt="alt text"></p><h2 id="安装-配置-switchyomega" tabindex="-1">安装 &amp; 配置 SwitchyOmega <a class="header-anchor" href="#安装-配置-switchyomega" aria-label="Permalink to &quot;安装 &amp; 配置 SwitchyOmega&quot;">​</a></h2><p><code>SwitchyOmega</code> 是一款浏览器插件，最近好像是由于安全问题不能直接在 chrome 插件商店下载了。<a href="https://github.com/FelisCatus/SwitchyOmega/releases" target="_blank" rel="noreferrer">地址</a> 选择 <code>.crx</code> 文件安装。</p><p><code>.crx</code> 大概率不能直接安装，不过也有其他方案。手动修改后缀为 <code>.zip</code> 然后再进行解压（有意思的是手动解压的时候还给我报错了，然后通过 <code>unzip</code> 又可以解压成功了）。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#FFA657;--shiki-light:#6F42C1;">unzip</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> SwitchyOmega_Chromium.zip</span><span style="--shiki-dark:#79C0FF;--shiki-light:#005CC5;"> -d</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;"> SwitchyOmega</span></span></code></pre></div><p>安装完成之后，点击插件的选项 - 新建<strong>代理服务器</strong>的情景模式 - 将代理服务器设置为 <code>127.0.0.1</code> 端口为 <code>8899</code> 即可。不经过代理的域名可以设置为空，或者按照自己的需求设置。</p><p><img src="'+p+'" alt="alt text"></p><p>当不适用时就使用系统代理或者直接连接，使用时选择对应的情景模式即可。</p><h2 id="项目调整" tabindex="-1">项目调整 <a class="header-anchor" href="#项目调整" aria-label="Permalink to &quot;项目调整&quot;">​</a></h2><p>这一步大概率之前就弄过，顺道提一下吧。以 <code>vite</code> 项目为例，增加 <code>env.test</code> 文件，配置测试环境 api 地址。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-dark-default github-light vp-code" tabindex="0"><code><span class="line"><span style="--shiki-dark:#E6EDF3;--shiki-light:#24292E;">VITE_GATEWAY_ORIGIN</span><span style="--shiki-dark:#FF7B72;--shiki-light:#D73A49;">=</span><span style="--shiki-dark:#A5D6FF;--shiki-light:#032F62;">//gateway.test.api</span></span></code></pre></div><p>在 <code>package.json</code> 中增加 <code>test</code> 命令，内容为 <code>&quot;test&quot;: &quot;vite build --mode test&quot;</code>。</p><h2 id="结束语" tabindex="-1">结束语 <a class="header-anchor" href="#结束语" aria-label="Permalink to &quot;结束语&quot;">​</a></h2><p>至此就可以在本地启动项目，进入验证阶段了。唯一不足的就是每次修改代码后都要刷新浏览器也可以看到最新的效果。</p><p><code>whistle</code> 的功能也不仅如此，可以用来抓包，修改请求，修改响应等。</p>',24)]))}const b=t(l,[["render",d]]);export{u as __pageData,b as default};
